## ✅ YouTube iFrame Embed – Schritt für Schritt

### Datei: `apps/youtube-search/index.html`

### 1️⃣ API-Key Code LÖSCHEN
```javascript
// ❌ ENTFERNEN:
const API_KEY = '...'; // oder ähnlich
const YOUTUBE_API_URL = 'https://www.googleapis.com/youtube/v3/search...';
```

### 2️⃣ Suchbox + iFrame Grundstruktur
```html
<!-- Suchbereich -->
<div id="searchContainer">
  <input type="text" id="searchInput" placeholder="Video-Titel eingeben..." style="width: 80%; padding: 10px;">
  <button onclick="searchYouTube()" style="padding: 10px 20px;">Suchen</button>
</div>

<!-- Ergebnisse -->
<div id="results" style="margin-top: 20px; display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 15px;"></div>

<!-- Video-Player -->
<div id="playerContainer" style="margin-top: 30px;">
  <iframe id="videoPlayer" width="100%" height="600" frameborder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowfullscreen style="display: none;"></iframe>
</div>
```

### 3️⃣ JavaScript – Suchfunktion (Invidious API)
```javascript
function searchYouTube() {
  const query = document.getElementById('searchInput').value.trim();
  if (!query) return;

  // Invidious API (Open-Source YouTube Alternative, keine Keys nötig!)
  fetch(`https://www.invidious.io/api/v1/search?q=${encodeURIComponent(query)}&type=video`)
    .then(r => r.json())
    .then(data => displayResults(data))
    .catch(err => console.error('Invidious Fehler:', err));
}

function displayResults(videos) {
  const resultsDiv = document.getElementById('results');
  resultsDiv.innerHTML = '';

  videos.forEach(video => {
    const card = document.createElement('div');
    card.style.cssText = 'border: 1px solid #ddd; padding: 10px; cursor: pointer; border-radius: 8px;';
    card.innerHTML = `<img src="${video.videoThumbnails?.[0]?.url || ''}" style="width: 100%; border-radius: 6px;" alt="${video.title}"><p style="font-size: 12px; margin: 8px 0 0 0; font-weight: bold;">${video.title}</p>`;
    card.onclick = () => playVideo(video.videoId);
    resultsDiv.appendChild(card);
  });
}

function playVideo(videoId) {
  // YouTube iFrame Embed
  const iFrame = document.getElementById('videoPlayer');
  iFrame.src = `https://www.youtube.com/embed/${videoId}`;
  iFrame.style.display = 'block';
  iFrame.scrollIntoView({ behavior: 'smooth' });
}
```

### ⚠️ Wichtig:
- **Invidious** ist kostenlos & braucht keinen API-Key
- **YouTube iFrame** funktioniert für alle öffentlichen Videos
- Falls Invidious ausfällt: Fallback auf YouTube-Suche (direkt zu youtube.com/results?search_query=...)

